xml.src:

@Component({
             selector   : 'app-root',
             imports    : [
               RouterOutlet,
               InuToast,
               InuMainHeader,
               InuFooter,
               InuPageLayout
             ],
             templateUrl: './app.html',
             styleUrl   : './app.scss'
           })
export class App implements OnInit {
  //...
  protected links               = signal<InuSiteLink[]>([
                                                          {
                                                            title   : 'Inugami Framework',
                                                            path    : 'https://inugami.io/inugami/framework',
                                                            external: true
                                                          }
                                                          //...
                                                        ]);

  protected asideLinks = signal<InuSiteLink[]>([
                                                 {
                                                   title   : 'GitHub',
                                                   path    : 'https://github.com/inugamiio/inugami-ng',
                                                   external: true,
                                                   target  : TARGET_BLANK,
                                                   icon    : 'git'
                                                 },
                                                 {
                                                   title: 'Icons',
                                                   path : '/icons',
                                                   icon : 'image'
                                                 },
                                                 //--- ACTIONS ---------------------------------------------------------
                                                 {
                                                   title   : 'Actions',
                                                   icon    : 'terminal',
                                                   children: [
                                                     {
                                                       links: [
                                                         {
                                                           title: 'inu-button',
                                                           path : '/actions/inu-button'
                                                         },
                                                         {
                                                           title: 'inu-copy',
                                                           path : '/actions/inu-copy'
                                                         }
                                                       ]
                                                     }
                                                   ]
                                                 },
                                                 //...
                                               ]);
}


@Component({
             templateUrl: './user-search.view.html',
             styleUrls  : ['./user-search.view.scss'],
             imports: [
                InugamiTemplateDirective,
                InuPageLayout,
                RouterOutlet
             ]
           })
export class UserSearchView {

}
